import { GoogleGenAI, Type } from "@google/genai";
import { Company, DuPontAnalysis, MetricYearData, NLPMeasures } from "../types";

/**
 * Utility function to handle retries with exponential backoff
 */
async function fetchWithRetry<T>(fn: () => Promise<T>, maxRetries: number = 3, initialDelay: number = 3000): Promise<T> {
  let attempt = 0;
  while (attempt <= maxRetries) {
    try {
      return await fn();
    } catch (error: any) {
      const isRateLimit = error?.status === 429 || 
                          error?.message?.includes("429") || 
                          error?.message?.includes("RESOURCE_EXHAUSTED") ||
                          error?.message?.includes("Quota");

      if (isRateLimit && attempt < maxRetries) {
        const delay = initialDelay * Math.pow(2, attempt);
        console.warn(`Rate limit hit. Retrying in ${delay}ms... (Attempt ${attempt + 1}/${maxRetries})`);
        await new Promise(resolve => setTimeout(resolve, delay));
        attempt++;
        continue;
      }
      throw error;
    }
  }
  throw new Error("Max retries exceeded");
}

export async function generateDuPontAnalysis(
  company: Company, 
  anchorYear: number, 
  isDeepDive: boolean = false,
  discrepancyNote?: string
): Promise<DuPontAnalysis> {
  const apiKey = process.env.API_KEY as string;

  return fetchWithRetry(async () => {
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `Perform a ${isDeepDive ? 'CRITICAL DEEP-DIVE' : 'high-precision'} financial and NLP analysis for ${company.name} (${company.symbol}) for anchor year ${anchorYear} and the previous two years. 

${isDeepDive ? `DISCREPANCY ALERT: ${discrepancyNote}. Please conduct an exhaustive search to resolve this variance.` : ''}

CRITICAL ACCURACY LOGIC:
For every financial number used (Revenue, Profit, Assets, Equity) for each of the 3 years:
1. Search the internet for the official reported figure for ${company.name}.
2. Compare identified values against official sources.
3. Record these details in the accuracyAudit array.
4. IMPORTANT: For each year, find and provide the direct URL to the official Annual Report PDF or official financial summary page on the company's IR website.

ROI PEER BENCHMARKING:
Identify the closest direct industry competitor (peer) for ${company.name} and retrieve their ROA and ROE for the year ${anchorYear}.

RISK PEER COMPARISON:
Identify peer median and top-quartile benchmarks within the ${company.sector} sector for Financial Risk (Leverage), Solvency (Index), and Business Risk (NLP evidence).

Return the result in strict JSON format.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            timeSeries: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  year: { type: Type.INTEGER },
                  revenue: { type: Type.NUMBER },
                  netProfit: { type: Type.NUMBER },
                  totalAssets: { type: Type.NUMBER },
                  totalEquity: { type: Type.NUMBER },
                  reportUrl: { type: Type.STRING, description: "Direct URL to the official annual report PDF or IR page for this year" }
                },
                required: ["year", "revenue", "netProfit", "totalAssets", "totalEquity"]
              }
            },
            peerROI: {
              type: Type.OBJECT,
              properties: {
                peerName: { type: Type.STRING },
                peerSymbol: { type: Type.STRING },
                roa: { type: Type.NUMBER },
                roe: { type: Type.NUMBER }
              },
              required: ["peerName", "peerSymbol", "roa", "roe"]
            },
            accuracyAudit: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  metric: { type: Type.STRING },
                  year: { type: Type.INTEGER },
                  identifiedValue: { type: Type.NUMBER },
                  verifiedValue: { type: Type.NUMBER },
                  variance: { type: Type.NUMBER },
                  status: { type: Type.STRING }
                },
                required: ["metric", "year", "identifiedValue", "verifiedValue", "variance", "status"]
              }
            },
            accuracySummary: { type: Type.STRING },
            peerRiskComparison: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  metric: { type: Type.STRING },
                  companyValue: { type: Type.STRING },
                  peerMedian: { type: Type.STRING },
                  topQuartile: { type: Type.STRING },
                  evidence: { type: Type.STRING }
                },
                required: ["metric", "companyValue", "peerMedian", "topQuartile", "evidence"]
              }
            },
            nlpData: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  year: { type: Type.INTEGER },
                  sentiment: { type: Type.NUMBER },
                  fli: { type: Type.NUMBER },
                  specificity: { type: Type.NUMBER },
                  sentenceLength: { type: Type.NUMBER },
                  depth: { type: Type.NUMBER },
                  unfamiliarity: { type: Type.NUMBER }
                },
                required: ["year", "sentiment", "fli", "specificity", "sentenceLength", "depth", "unfamiliarity"]
              }
            },
            narrative: {
              type: Type.OBJECT,
              properties: {
                section1: { type: Type.STRING },
                section2: { type: Type.STRING },
                section3: { type: Type.STRING },
                section4: { type: Type.STRING },
                qAndA: {
                  type: Type.OBJECT,
                  properties: {
                    roe_trend: { type: Type.STRING },
                    roe_peer: { type: Type.STRING },
                    roe_persistent: { type: Type.STRING },
                    driver_dominance: { type: Type.STRING },
                    driver_peer: { type: Type.STRING },
                    risk_trend: { type: Type.STRING },
                    risk_peer: { type: Type.STRING },
                    nlp_sentiment: { type: Type.STRING },
                    nlp_specificity: { type: Type.STRING },
                    nlp_complexity: { type: Type.STRING },
                    nlp_peer: { type: Type.STRING }
                  }
                }
              }
            },
            forecasts: {
              type: Type.OBJECT,
              properties: {
                roa: { 
                  type: Type.OBJECT, 
                  properties: { base: { type: Type.NUMBER }, upside: { type: Type.NUMBER }, downside: { type: Type.NUMBER } } 
                },
                roe: { 
                  type: Type.OBJECT, 
                  properties: { base: { type: Type.NUMBER }, upside: { type: Type.NUMBER }, downside: { type: Type.NUMBER } } 
                }
              }
            }
          },
          required: ["timeSeries", "accuracyAudit", "accuracySummary", "nlpData", "narrative", "peerRiskComparison", "peerROI"]
        }
      }
    });

    const text = response.text;
    if (typeof text !== 'string') {
      throw new Error("Invalid API response format.");
    }

    const rawData = JSON.parse(text);
    const sources: { title: string; uri: string }[] = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({ title: chunk.web.title, uri: chunk.web.uri });
        }
      });
    }

    const computedTimeSeries: MetricYearData[] = rawData.timeSeries.map((d: any, i: number, arr: any[]) => {
      const prev = i < arr.length - 1 ? arr[i+1] : null;
      const avgAssets = prev ? (d.totalAssets + prev.totalAssets) / 2 : d.totalAssets;
      const avgEquity = prev ? (d.totalEquity + prev.totalEquity) / 2 : d.totalEquity;

      return {
        ...d,
        margin: d.netProfit / d.revenue,
        turnover: d.revenue / avgAssets,
        roa: d.netProfit / avgAssets,
        leverage: avgAssets / avgEquity,
        roe: d.netProfit / avgEquity,
        reportUrl: d.reportUrl
      };
    });

    const nlpMap: Record<number, NLPMeasures> = {};
    rawData.nlpData.forEach((n: any) => {
      nlpMap[n.year] = {
        sentiment: n.sentiment,
        fli: n.fli,
        specificity: n.specificity,
        sentenceLength: n.sentenceLength,
        depth: n.depth,
        unfamiliarity: n.unfamiliarity
      };
    });

    return {
      company,
      anchorYear,
      timeSeries: computedTimeSeries,
      nlpData: nlpMap,
      sources,
      accuracyAudit: rawData.accuracyAudit,
      accuracySummary: rawData.accuracySummary,
      peerROI: rawData.peerROI,
      risk: {
        financial: "Risk assessment validated via multi-source verification.",
        solvencyIndex: 0.82,
        business: { legal: 0.2, tax: 0.1, macro: 0.5, firmSpecific: 0.2 },
        summary: rawData.narrative.section3,
        peerComparison: rawData.peerRiskComparison
      },
      narrative: rawData.narrative,
      forecasts: rawData.forecasts || { roa: { base: 0.05, upside: 0.07, downside: 0.03 }, roe: { base: 0.12, upside: 0.15, downside: 0.09 } }
    };
  });
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { FTSE100_CONSTITUENTS, YEARS, ExtendedCompany, METRIC_DEFINITIONS } from './constants';
import { DuPontAnalysis } from './types';
import { generateDuPontAnalysis } from './services/geminiService';
import MetricCharts from './components/MetricCharts';
import DuPontMap from './components/DuPontMap';
import NLPTrendCharts from './components/NLPTrendCharts';

const CACHE_PREFIX = "dupont_cache_";

const App: React.FC = () => {
  const [selectedSymbol, setSelectedSymbol] = useState(FTSE100_CONSTITUENTS[0].symbol);
  const [anchorYear, setAnchorYear] = useState(YEARS[0]);
  const [analysis, setAnalysis] = useState<DuPontAnalysis | null>(null);
  const [loading, setLoading] = useState(false);
  const [statusMessage, setStatusMessage] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [explanationId, setExplanationId] = useState<string | null>(null);
  const [showDisclaimer, setShowDisclaimer] = useState(false);
  const [showMethodology, setShowMethodology] = useState(false);
  const [showProjectInfo, setShowProjectInfo] = useState(false);

  // Pre-cache State
  const [preCaching, setPreCaching] = useState(false);
  const [preCacheProgress, setPreCacheProgress] = useState({ current: 0, total: FTSE100_CONSTITUENTS.length, symbol: "" });
  const isPreCachingRef = useRef(false);

  const selectedCompany = useMemo(() => 
    FTSE100_CONSTITUENTS.find(c => c.symbol === selectedSymbol) as ExtendedCompany || FTSE100_CONSTITUENTS[0]
  , [selectedSymbol]);

  const filteredConstituents = useMemo(() => 
    FTSE100_CONSTITUENTS.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      c.symbol.toLowerCase().includes(searchTerm.toLowerCase())
    )
  , [searchTerm]);

  const getCachedAnalysis = useCallback((symbol: string, year: number): DuPontAnalysis | null => {
    const key = `${CACHE_PREFIX}${symbol}_${year}`;
    const cached = localStorage.getItem(key);
    if (cached) {
      try {
        return JSON.parse(cached);
      } catch {
        return null;
      }
    }
    return null;
  }, []);

  const setCachedAnalysis = useCallback((symbol: string, year: number, data: DuPontAnalysis) => {
    const key = `${CACHE_PREFIX}${symbol}_${year}`;
    localStorage.setItem(key, JSON.stringify(data));
  }, []);

  const calculateDiscrepancy = (oldData: DuPontAnalysis, newData: DuPontAnalysis) => {
    const oldRoe = oldData.timeSeries[0].roe;
    const newRoe = newData.timeSeries[0].roe;
    const oldProfit = oldData.timeSeries[0].netProfit;
    const newProfit = newData.timeSeries[0].netProfit;

    const roeDiff = Math.abs(newRoe - oldRoe) / (oldRoe || 1);
    const profitDiff = Math.abs(newProfit - oldProfit) / (oldProfit || 1);

    return {
      significant: roeDiff > 0.01 || profitDiff > 0.01,
      message: `ROE shifted by ${(roeDiff * 100).toFixed(2)}%, Net Profit shifted by ${(profitDiff * 100).toFixed(2)}%`
    };
  };

  const runAnalysis = async (forceRefresh: boolean = false, targetCompany: ExtendedCompany = selectedCompany, targetYear: number = anchorYear) => {
    const cached = getCachedAnalysis(targetCompany.symbol, targetYear);

    if (cached && !forceRefresh) {
      if (targetCompany.symbol === selectedSymbol && targetYear === anchorYear) {
        setAnalysis(cached);
      }
      return cached;
    }

    const isCurrentView = targetCompany.symbol === selectedSymbol && targetYear === anchorYear;
    if (isCurrentView) {
      setLoading(true);
      setStatusMessage("Validating Financial Data...");
    }

    try {
      let result = await generateDuPontAnalysis(targetCompany, targetYear);

      if (forceRefresh && cached) {
        const discrepancy = calculateDiscrepancy(cached, result);
        if (discrepancy.significant) {
          if (isCurrentView) setStatusMessage("Significant Deviation Detected. Initializing Deep-Dive Search...");
          result = await generateDuPontAnalysis(targetCompany, targetYear, true, discrepancy.message);
        }
      }

      if (isCurrentView) setAnalysis(result);
      setCachedAnalysis(targetCompany.symbol, targetYear, result);
      return result;
    } catch (err: any) {
      const msg = err?.message?.includes("429") || err?.message?.includes("RESOURCE_EXHAUSTED")
        ? "API limit reached. Please wait a moment and try again."
        : "Performance analysis is currently unavailable. Please check your connection and try again.";
      if (isCurrentView) alert(msg);
      throw err;
    } finally {
      if (isCurrentView) {
        setLoading(false);
        setStatusMessage("");
      }
    }
  };

  const startPreCache = async () => {
    if (isPreCachingRef.current) {
      isPreCachingRef.current = false;
      setPreCaching(false);
      return;
    }

    isPreCachingRef.current = true;
    setPreCaching(true);
    let completed = 0;

    for (const company of FTSE100_CONSTITUENTS) {
      if (!isPreCachingRef.current) break;

      const cached = getCachedAnalysis(company.symbol, anchorYear);
      setPreCacheProgress({ current: completed + 1, total: FTSE100_CONSTITUENTS.length, symbol: company.symbol });

      if (!cached) {
        try {
          await runAnalysis(false, company, anchorYear);
          // Increased delay to 6s to be safe with standard quotas
          await new Promise(r => setTimeout(r, 6000));
        } catch (e: any) {
          console.error(`Failed to pre-cache ${company.symbol}`, e);
          if (e?.message?.includes("429") || e?.message?.includes("RESOURCE_EXHAUSTED")) {
            // If we hit a hard limit even with retries, pause longer
            await new Promise(r => setTimeout(r, 15000));
          }
        }
      }
      completed++;
    }

    isPreCachingRef.current = false;
    setPreCaching(false);
    setPreCacheProgress(prev => ({ ...prev, current: completed, symbol: "Complete" }));
  };

  useEffect(() => {
    const cached = getCachedAnalysis(selectedSymbol, anchorYear);
    if (cached) {
      setAnalysis(cached);
    } else {
      runAnalysis(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedSymbol, anchorYear]);

  const downloadReport = () => {
    if (!analysis) return;
    const blob = new Blob([JSON.stringify(analysis, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `DuPont_Report_${analysis.company.symbol}_${analysis.anchorYear}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const currentExplanation = explanationId ? METRIC_DEFINITIONS[explanationId] : null;

  return (
    <div className="min-h-screen bg-slate-50 pb-40 font-sans selection:bg-indigo-100 selection:text-indigo-900">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 shadow-sm transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 py-3 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">

            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-white rounded-xl p-1.5 flex items-center justify-center shadow-md border border-slate-100 flex-shrink-0 overflow-hidden group">
                <img 
                  src={`https://logo.clearbit.com/${selectedCompany.domain}`} 
                  alt=""
                  className="w-full h-full object-contain transition-transform group-hover:scale-110"
                  onError={(e) => {
                    (e.target as HTMLImageElement).src = `https://ui-avatars.com/api/?name=${selectedCompany.name}&background=6366f1&color=fff&size=128&bold=true`;
                  }}
                />
              </div>
              <div>
                <h1 className="text-xl font-black text-slate-900 leading-none mb-1">
                  {selectedCompany.name}
                </h1>
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-bold bg-slate-900 text-white px-1.5 py-0.5 rounded tracking-tighter uppercase">
                    {selectedCompany.symbol}
                  </span>
                  <p className="text-xs font-semibold text-indigo-600 uppercase tracking-wider">
                    Analysis Terminal
                  </p>
                </div>
              </div>
            </div>

            <div className="flex flex-wrap items-center gap-3">
              <div className="relative group">
                <input 
                  type="text"
                  placeholder="Find company..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-4 pr-10 py-2.5 bg-slate-100 border border-transparent rounded-xl focus:ring-2 focus:ring-indigo-500 focus:bg-white w-full md:w-48 text-sm font-medium transition-all"
                />
                <svg className="w-4 h-4 absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
                {searchTerm && (
                   <div className="absolute top-full left-0 right-0 mt-2 bg-white border border-slate-200 rounded-2xl shadow-2xl max-h-80 overflow-y-auto z-50 animate-in slide-in-from-top-2 duration-200">
                     {filteredConstituents.map(c => (
                       <button
                         key={c.symbol}
                         onClick={() => {
                           setSelectedSymbol(c.symbol);
                           setSearchTerm("");
                         }}
                         className="w-full text-left px-4 py-3 hover:bg-indigo-50 border-b border-slate-50 last:border-none transition-colors"
                       >
                         <div className="flex items-center gap-3">
                            <img 
                              src={`https://logo.clearbit.com/${c.domain}`} 
                              alt="" 
                              className="w-6 h-6 rounded flex-shrink-0"
                              onError={(e) => (e.target as HTMLImageElement).src = `https://ui-avatars.com/api/?name=${c.name}&background=f1f5f9&color=6366f1&size=64`}
                            />
                            <div>
                              <div className="text-sm font-bold text-slate-900">{c.name}</div>
                              <div className="text-[10px] font-bold text-slate-400 uppercase">{c.symbol}</div>
                            </div>
                         </div>
                       </button>
                     ))}
                   </div>
                )}
              </div>

              <select 
