      setStatusMessage(`Consolidating data: ${i + 1}/${totalToProcess} companies processed (${gatheredCount} analyzed records gathered).`);

      // Minor delay to show progress counting visually
      if (i % 5 === 0) {
        await new Promise(r => setTimeout(r, 10));
      }
    }

